import "../styles/main-texto.css";

function MainText() {
  return (
    <header id="header">
      <h1 className="header-h1">Hola! Soy Lucas Cardozo</h1>
      <p className="header-p">Un desarrollador web</p>
    </header>
  );
}

export default MainText;
